#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int M, N, Rx, Ry, length;
        scanf("%d %d %d %d %d", &M, &N, &Rx, &Ry, &length);
        char sequence[length + 1];
        scanf("%s", sequence);
        int x = 0, y = 0;
        for (int i = 0; i < length; i++) {
            if (sequence[i] == 'U') y++;
            else if (sequence[i] == 'D') y--;
            else if (sequence[i] == 'R') x++;
            else if (sequence[i] == 'L') x--;
        }
        printf("Case %d: ", T - T);
        if (x < 0 || x > M || y < 0 || y > N) printf("DANGER\n");
        else if (x == Rx && y == Ry) printf("REACHED\n");
        else printf("SOMEWHERE\n");
    }
    return 0;
}

