            int x = 0, y = 0;
            for (int i = 0; i < length; i++) {
                if (sequence.charAt(i) == 'U') y++;
                else if (sequence.charAt(i) == 'D') y--;
                else if (sequence.charAt(i) == 'R') x++;
                else if (sequence.charAt(i) == 'L') x--;
            }
            System.out.print("Case " + (t + 1) +": ");
            if (x < 0 || x > M || y < 0 || y > N) System.out.println("DANGER");
            else if (x == Rx && y == Ry) System.out.println("REACHED");
